import type { CurriculumModule, Lesson } from '@/lib/types';

// Helper to build a lesson object concisely
function L(id: string, slug: string, title: string, type: Lesson['type'], mins: number, order: number, content: string, keyPoints?: string[]): Lesson {
    return { id, slug, title, type, durationMinutes: mins, content, keyPoints, order };
}

