// Helper: get a module by slug
export function getModuleBySlug(slug: string): CurriculumModule | undefined {
    return FULL_CURRICULUM.find(m => m.slug === slug);
}

// Helper: get a lesson by module slug + lesson slug
export function getLessonBySlug(moduleSlug: string, lessonSlug: string): { module: CurriculumModule; lesson: Lesson } | undefined {
    const mod = getModuleBySlug(moduleSlug);
    if (!mod) return undefined;
    const lesson = mod.lessons.find(l => l.slug === lessonSlug);
    if (!lesson) return undefined;
    return { module: mod, lesson };
}

// Helper: total stats
export function getCurriculumStats() {
    const totalModules = FULL_CURRICULUM.length;
    const totalLessons = FULL_CURRICULUM.reduce((sum, m) => sum + m.lessons.length, 0);
    const totalHours = FULL_CURRICULUM.reduce((sum, m) => sum + m.estimatedHours, 0);
    return { totalModules, totalLessons, totalHours };
}
